changeSet.sql:
CREATE SERVER IF NOT EXISTS dpc_attribution
FOREIGN DATA WRAPPER postgres_fdw
OPTIONS (host 'localhost', dbname 'dpc_attribution', port '5432');

CREATE USER MAPPING IF NOT EXISTS FOR "${QUEUE_DB_USER}"
SERVER dpc_attribution
OPTIONS (user '${ATTRIBUTION_DB_USER}', password '${ATTRIBUTION_DB_PASS}');

GRANT SELECT ON unique_providers_served_all_time TO PUBLIC;
GRANT SELECT ON benes_requested_last_week TO PUBLIC;
GRANT SELECT ON unique_benes_served_last_week TO PUBLIC;
GRANT SELECT ON bulk_calls_made_last_week TO PUBLIC;
GRANT SELECT ON patient_everything_requests_last_week TO PUBLIC;
GRANT SELECT ON since_requests_last_week TO PUBLIC;
